package com.example.oauthclient;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;

@SpringBootApplication
public class OAuthClientApplication {

    public static void main(String[] args) {
        SpringApplication.run(OAuthClientApplication.class, args);
    }

    @Bean
    public OAuthConfig oauthConfig() {
        return new OAuthConfig(
                "https://authorization-server.example.com/oauth2/authorize",
                "your-client-id",
                "https://your-app.example.com/oauth/callback",
                "openid profile email"
        );
    }
}

class OAuthConfig {
    private final String authorizationEndpoint;
    private final String clientId;
    private final String redirectUri;
    private final String scope;

    public OAuthConfig(String authorizationEndpoint, String clientId, String redirectUri, String scope) {
        this.authorizationEndpoint = authorizationEndpoint;
        this.clientId = clientId;
        this.redirectUri = redirectUri;
        this.scope = scope;
    }

    public String getAuthorizationEndpoint() {
        return authorizationEndpoint;
    }

    public String getClientId() {
        return clientId;
    }

    public String getRedirectUri() {
        return redirectUri;
    }

    public String getScope() {
        return scope;
    }
}

@Controller
class OAuthController {

    private final OAuthConfig config;

    public OAuthController(OAuthConfig config) {
        this.config = config;
    }

    @GetMapping("/oauth/login")
    public void login(HttpServletResponse response) throws IOException {
        String authorizationUrl = buildAuthorizationUrl();
        response.sendRedirect(authorizationUrl);
    }

    @GetMapping("/oauth/callback")
    public ResponseEntity<String> callback(@RequestParam(required = false) String code,
                                           @RequestParam(required = false) String error) {
        if (error != null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body("OAuth authorization failed: " + error);
        }

        if (code == null || code.isBlank()) {
            return ResponseEntity.badRequest().body("Missing authorization code");
        }

        return ResponseEntity.ok("Authorization code received: " + code);
    }

    private String buildAuthorizationUrl() {
        return config.getAuthorizationEndpoint()
                + "?client_id=" + encode(config.getClientId())
                + "&redirect_uri=" + encode(config.getRedirectUri())
                + "&scope=" + encode(config.getScope())
                + "&response_type=" + encode("code");
    }

    private String encode(String value) {
        return URLEncoder.encode(value, StandardCharsets.UTF_8);
    }
}